/* -------------------------------------------------------------------- */
/* -- Composant permettant de lire le CSV et d'updater la BDD Firebase -*/
/* -------------------------------------------------------------------- */
import Papa from "papaparse";
import { db } from '../config/firebase';
import { doc, setDoc, updateDoc, arrayUnion, getDoc } from 'firebase/firestore';
import React, { useState, useEffect } from 'react';


async function processBatch(batch, quarterId) {
    for (const item of batch) {
        // call Send logic here
        await Send(item, quarterId);
    }
}

async function Send(item, quarterId) {
    const obj = item;
    const id = obj.ID;
    const namecity = obj['CITY NAME'];
    const nameroute = obj['ROUTE  NAME']; 
    let nbrsessions = obj['NB ROUTE VIEWED'];
    console.log("Item:", item); // Log the entire item
    
    console.log("Route Name:", nameroute); // Log the route name
    const ID = String(id);
    const NAMECITY = String(namecity);
    const NAMEROUTE = String(nameroute);
    const NBRSESSIONS = Number(nbrsessions);

    try {
        const routeRef = doc(db, "Routes", ID);
        const routeDoc = await getDoc(routeRef);
        
        if (routeDoc.exists()) {
            const routeData = routeDoc.data();
            // Check if the nameRoute in Firestore matches the CSV
            if (routeData.nameRoute !== NAMEROUTE) {
                // If not, update the document with the CSV value
                await updateDoc(routeRef, {
                    id: ID,
                    nameCity: NAMECITY,
                    nameRoute: NAMEROUTE
                });
            }
        } else {
            // If the route document does not exist, create a new one
            await setDoc(routeRef, {
                id: ID,
                nameCity: NAMECITY,
                nameRoute: NAMEROUTE
            });
        }

        const statsRef = doc(db, "Routes", ID, "statistics", quarterId);
        try {
            await updateDoc(statsRef, { nbrSessions: NBRSESSIONS });
        } catch (error) {
            if (error.code === "not-found") {
                await setDoc(statsRef, { nbrSessions: NBRSESSIONS });
            } else {
                throw error;
            }
        }

        const cityRef = doc(db, "City", NAMECITY);
        try {
            const cityDoc = await getDoc(cityRef);
            if (cityDoc.exists()) {
                // If the city document exists, update it
                await updateDoc(cityRef, { Routes: arrayUnion(ID), nameCity: NAMECITY }, { merge: true });
            } else {
                // If the city document does not exist, create a new one
                await setDoc(cityRef, { Routes: [ID], nameCity: NAMECITY });
            }
        } catch (error) {
            console.error("Error handling city document: ", error);
        }

        alert("Data Successfully Submitted for ID: " + ID);
    } catch (error) {
        console.error("Error updating/adding document: ", error);
    }
}


function Parse() {
    const [parsedData, setParsedData] = useState([]);
    const [tableRows, setTableRows] = useState([]);
    const [values, setValues] = useState([]);
    const [selectedQuarter, setSelectedQuarter] = useState("Q1");
    const [selectedYear, setSelectedYear] = useState("2020");
    const [progress, setProgress] = useState(0);

    useEffect(() => {
        if (parsedData.length > 0) {
            const batchSize = 25;
            const totalBatches = Math.ceil(parsedData.length / batchSize);
            const quarterId = `${selectedQuarter}_${selectedYear}`;

            for (let i = 0; i < totalBatches; i++) {
                const batch = parsedData.slice(i * batchSize, (i + 1) * batchSize);
                processBatch(batch, quarterId).then(() => {
                    // Update progress after each batch
                    setProgress((prevProgress) => prevProgress + (100 / totalBatches));
                });
            }
        }
    }, [parsedData, selectedQuarter, selectedYear]);


    const changeHandler = (event) => {
        Papa.parse(event.target.files[0], {
            header: true,
            skipEmptyLines: true,
            complete: function (results) {
                const rowsArray = [];
                const valuesArray = [];

                results.data.forEach((d) => {
                    rowsArray.push(Object.keys(d));
                    valuesArray.push(Object.values(d));
                });

                setParsedData(results.data);
                setProgress(0);
                setTableRows(rowsArray[0]);
                setValues(valuesArray);

                const quarterId = `${selectedQuarter}_${selectedYear}`;
                results.data.forEach((item) => Send(item, quarterId));
            }
        });
    };

    return (
        <div>
            <select onChange={(e) => setSelectedQuarter(e.target.value)}>
                <option value="Q1">Q1</option>
                <option value="Q2">Q2</option>
                <option value="Q3">Q3</option>
                <option value="Q4">Q4</option>
            </select>

            <select onChange={(e) => setSelectedYear(e.target.value)}>
                {Array.from({ length: 11 }, (_, i) => 2020 + i).map((year) => (
                    <option key={year} value={year}>
                        {year}
                    </option>
                ))}
            </select>

            <input
                type="file"
                name="file"
                onChange={changeHandler}
                accept=".csv"
                style={{ display: "block", margin: "10px auto" }}
            />
            <progress value={progress} max="100"></progress>
            <table>
                <thead>
                    <tr>
                        {tableRows.map((rows, index) => (
                            <th key={index}>{rows}</th>
                        ))}
                    </tr>
                </thead>
                <tbody>
                    {values.map((value, index) => (
                        <tr key={index}>
                            {value.map((val, i) => (
                                <td key={i}>{val}</td>
                            ))}
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
}

export default Parse;
